def evaluate(exp):
    if isinstance(exp, int):
        return exp
    operator = exp[0]
    operands = []
    for sub_exp in exp[1:]:
        operands.append(evaluate(sub_exp))
    return apply_operator(operator, operands)


def apply_operator(operator, operands):
    if operator == "+":
        return sum(operands)
    if operator == "*":
        total = 1
        for value in operands:
            total = total * value
        return total
    raise ValueError(operator)


expression = ["*", ["+", 1, 2], ["+", 2, 3]]
answer = evaluate(expression)
print(answer)
